#!/bin/bash
set -euo pipefail
install -d -m 755 /opt/robodynamics/ai-tutor/tutor-api/app/services
cat <<B64 | base64 -d > /opt/robodynamics/ai-tutor/tutor-api/app/services/generic_course_engine.py

B64
cat <<B64 | base64 -d > /opt/robodynamics/ai-tutor/tutor-api/app/services/course_template_client.py

B64
chown tomcat:tomcat /opt/robodynamics/ai-tutor/tutor-api/app/services/generic_course_engine.py /opt/robodynamics/ai-tutor/tutor-api/app/services/course_template_client.py || true
chmod 644 /opt/robodynamics/ai-tutor/tutor-api/app/services/generic_course_engine.py /opt/robodynamics/ai-tutor/tutor-api/app/services/course_template_client.py
systemctl restart rd-ai-tutor-api
sleep 2
echo "API=$(systemctl is-active rd-ai-tutor-api || true)"
python3 - <<PY
import importlib.util
for p in [
 '/opt/robodynamics/ai-tutor/tutor-api/app/services/generic_course_engine.py',
 '/opt/robodynamics/ai-tutor/tutor-api/app/services/course_template_client.py',
]:
    spec = importlib.util.spec_from_file_location('m', p)
    m = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(m)
print('PY_IMPORT_OK')
PY
